private boolean isNullObject(JsonParser p) throws IOException {
    switch (p.getCurrentToken()) {
        case VALUE_STRING:
            String text = p.getText().trim();
            return text.isEmpty();
        case VALUE_NULL:
            return true;
        // Add more cases if needed for other types considered as null objects
        default:
            return false;
    }
}

